class Solution {
public:
    vector<int> numsSameConsecDiff(int n, int k) {
        vector<int> res;
        for(int i = 1; i <= 9; i++) {
            dfs(i, n - 1, k, res);
        }
        return res;
    }
    void dfs(int num, int n, int k, vector<int>& res) {
        if(n == 0) {
            res.push_back(num);
            return;
        }
        int last = num % 10;
        if(k == 0) {
            for(int i = 0; i <= 9; i++) {
                dfs(num * 10 + i, n - 1, k, res);
            }
        } else {
            if(last - k >= 0) {
                dfs(num * 10 + (last - k), n - 1, k, res);
            }
            if(last + k <= 9) {
                dfs(num * 10 + (last + k), n - 1, k, res);
            }
        }
    }
};
